from langchain_core.tools import tool
from langchain.agents import AgentExecutor, create_tool_calling_agent
from langchain_core.prompts import ChatPromptTemplate, MessagesPlaceholder
from langchain_openai import ChatOpenAI
import json

@tool
def search_papers(topic: str) -> str:
    """Search academic papers on a topic. Returns title and abstract."""
    return json.dumps([{
        'title': f'Attention Is All You Need: {topic} Analysis',
        'abstract': f'We study {topic} in transformer architectures...'
    }, {
        'title': f'Efficient {topic} via Sparse Attention',
        'abstract': f'A sparse approach to {topic} reduces complexity...'
    }])

@tool
def count_words(text: str) -> str:
    """Count the number of words in a text string."""
    return str(len(text.split()))

llm = ChatOpenAI(model='gpt-4o-mini', temperature=0)
tools = [search_papers, count_words]
prompt = ChatPromptTemplate.from_messages([
    ('system', 'You are a research assistant.'),
    ('human', '{input}'),
    MessagesPlaceholder('agent_scratchpad'),
])
agent = create_tool_calling_agent(llm, tools, prompt)
executor = AgentExecutor(agent=agent, tools=tools, verbose=True)
print(executor.invoke({'input': 'Find papers about transformer attention, then tell me how many words are in the title of the first paper.'})['output'])
```
